#include &lt;iostream&gt;
#include&lt;cstdio&gt;
#include&lt;stdlib.h&gt;
typedef struct node{
    int data;
    struct node *next;
}link,*linkednode;
// 在此使用头插法完成链表的建立
void CreateLink(linkednode &amp;L)
{
    linkednode s;
    L=(linkednode)malloc(sizeof(link));
    L-&gt;next=NULL;
    for(int i=0;i&lt;10;i++)
    {
        s=(linkednode)malloc(sizeof(link));
        s-&gt;data=i;
        // 插入结点信息
        s-&gt;next=L-&gt;next;
        L-&gt;next=s;
    }
}
// 输出结点信息
void printLinkinfo(linkednode &amp;L)
{
    linkednode temp;
    temp =(linkednode)malloc(sizeof(link));
    temp=L;
    while(temp-&gt;next)
    {
        printf(&quot;%d&quot;,temp-&gt;data);
        temp=temp-&gt;next;
    }
}
// 使用尾插法建立链表的操作
void CreateLink2(linkednode &amp;L)
{
    linkednode s,t;
    L=(linkednode)malloc(sizeof(link));
    L-&gt;next=NULL;
    t=L;
    int i;
    for( i=0;i&lt;10;i++)
    {
        s=(linkednode)malloc(sizeof(link));
        s-&gt;data=i;
        s-&gt;next=NULL;
        t-&gt;next=s;
        t=s;
    }
}

// 删除结点信息
void deleteinfo(linkednode &amp;L,int i)
{
    linkednode temp ,t;
    int j=0;
    temp=(linkednode)malloc(sizeof(link));
    temp=L;
    while(temp-&gt;next&amp;&amp;(j&lt;i-1))
   {
       temp =temp-&gt;next;
       j++;
   }
    t=temp-&gt;next;
    temp-&gt;next=t-&gt;next;
    printf(&quot;删除的数据为%d&quot;,t-&gt;data);
}
void insertinfo(linkednode &amp;L,int loc,int e)
{
    int j=0;
    linkednode temp,s;
    temp=L;
    while(temp-&gt;next&amp;&amp;j&lt;(loc-1))
    {
        temp=temp-&gt;next;
        j++;
    }
    s=(linkednode)malloc(sizeof(link));
    s-&gt;data=e;
    s-&gt;next=temp-&gt;next;
    temp-&gt;next=s;
}
int main()
{
    link *L=NULL;
    // 头插法
    //CreateLink(L);
    //尾插法
    CreateLink2(L);
    // 输出信息
    printLinkinfo(L);
    printf(&quot;\n&quot;);
    deleteinfo(L,3);
    printf(&quot;\n&quot;);
    printLinkinfo(L);
    printf(&quot;\n&quot;);
    insertinfo(L,3,6);
    printLinkinfo(L);
    return 0;
}

最小生成树的建立——Prim算法  
概述生成树的概念
要建立最小生成树，首先要知道什么是生成树，了解生成树的概念才可以假设在连通图G中有n个顶点， 将G中的n-1条边 构成无回路的连通图称为生成树。

最小生成树的概念
图的生成树不是唯一的，在一个图中可能存在多个生成树，将个边权值相加之和最小的生成树， 称为最小生成树。

Prim算法
思路：Prim算法将顶点分为两部分，U和V-U，U中的顶点代表当前生成最小生成树的顶点，V—U就是没有处理过的顶点，起始时将全部的顶点之间的边作为候选边，依次从中选取权值最小的边作为最小生成树的边，不断修正U，直到得到构成最小生成树全部的顶点。

prim实现的过程设置关键数组
设置lowcost数组来存储边的权值，如果lowcost[i]=0表示 表名i就在U中，已经找构成最小生成树的点。
closevertex数组表示构成最小生成树相邻的顶点，理解当前构成最小生成的前驱，这个具体在运行的结果中看到，一会在看到输出结果是详细解释。

